const account = $('Fetch Onboarding Accounts').item.json;
const progress = $('Fetch Milestone Progress').item.json;

const milestones = [
  { name: 'Account Setup', key: 'account_setup', target_day: 1 },
  { name: 'First Login', key: 'first_login', target_day: 2 },
  { name: 'Integration Connected', key: 'integration_setup', target_day: 7 },
  { name: 'Training Completed', key: 'training_complete', target_day: 14 },
  { name: 'First Value Moment', key: 'first_value', target_day: 21 },
  { name: 'Go-Live', key: 'go_live', target_day: 30 }
];

const startDate = new Date(account.onboarding_start);
const daysSinceStart = Math.floor((Date.now() - startDate.getTime()) / (1000*60*60*24));

const atRisk = [];
const completed = [];
const upcoming = [];

for (const m of milestones) {
  const done = progress[m.key]?.completed;
  if (done) {
    completed.push(m.name);
  } else if (daysSinceStart >= m.target_day) {
    atRisk.push({ ...m, days_overdue: daysSinceStart - m.target_day });
  } else {
    upcoming.push({ ...m, days_until: m.target_day - daysSinceStart });
  }
}

return [{
  json: {
    account_id: account.id,
    account_name: account.name,
    contact_email: account.primary_contact_email,
    contact_name: account.primary_contact_name,
    csm_email: account.csm_email,
    days_in_onboarding: daysSinceStart,
    completed,
    at_risk: atRisk,
    upcoming,
    overall_status: atRisk.length > 0 ? 'at_risk' : 'on_track',
    completion_percent: Math.round((completed.length / milestones.length) * 100)
  }
}];

